    String groupsName = request.getParameter("groupsName");

    String urlType =request.getParameter("urlType");//"actionButton" or "webURL", default is webURL
    if(urlType ==null) urlType ="webURL";


    if(user==null || !user.ifApManager(apname)) return;

    List<String> groupNames = Encoder.transferJoinStrToList(groupsName, ",");

    MenuConfiguration mc= Account.getInstance(apname).getMenuConfiguration();
    List<MenuSet> menuSetList=mc.getMenuSets();

    int menuSetIndex= Encoder.parseInt(request.getParameter("msi"),MenuSet.DEFAULT_MENUSET);
    String path=request.getParameter("path");

    MenuSet selectedMenuSet=menuSetList.get(menuSetIndex);
    if(selectedMenuSet==null){
        out.println("Menu set deleted.");
        return;
    }

    MenuTab selectedMenuTab=selectedMenuSet.getTab(path);
    if(selectedMenuTab==null){
        out.println("Tab deleted.");
        return;
    }

    String deleteUrlId=request.getParameter("durlId");
    if(deleteUrlId!=null){
        if(selectedMenuTab.removeURL(deleteUrlId)){
            selectedMenuTab.save();
        }
        return;
    }

    String name=request.getParameter("name");
    String url=request.getParameter("url");
    if(name==null || url==null || name.isEmpty() || url.isEmpty()) return;

    String urlId=request.getParameter("urlId");
    MenuURL menuURL=selectedMenuTab.getURL(urlId);
    if(menuURL==null){
        menuURL=new MenuURL(name,url,mc, groupNames);
        menuURL.setUrlType(urlType);
        selectedMenuTab.addURL(menuURL);
        selectedMenuTab.save();
    }
    else{
        menuURL.setName(name);
        menuURL.setURL(url);
        menuURL.setGroupsName(groupNames);
        menuURL.save();
    }


